let horaInicio = $json.hora_inicio;
let duracionMin = parseInt($json.duracion || 0);

let [horas, minutos] = horaInicio.split(':').map(Number);

minutos += duracionMin;

if (minutos >= 60) {
    horas += Math.floor(minutos / 60);
    minutos = minutos % 60;
}

if (horas >= 24) {
    horas = horas % 24;
}

const horaFin = `${String(horas).padStart(2, '0')}:${String(minutos).padStart(2, '0')}`;

return {
    ...$json,
    hora_fin: horaFin
};

// resultado de la búsqueda del calendario
const items = $input.all();

const datosPaciente = $("Calcular Hora fin").first().json;

// Verifica si calendar encontro un evento real con ID
const hayEvento = items.some(i => i.json && i.json.id);

// Devuelve el JSON con la bandera de disponibilidad
return [{
    json: {
        ...datosPaciente,
        disponible: !hayEvento
    }
}];

const datosAgente = $("AI Agent").first().json;
const texto = datosAgente.output || "";

//Extraccion datos que el usuario nos dio para cancelar
const matchFecha = texto.match(/fecha:\s*([\d-]+)/i);
const matchHora = texto.match(/hora:\s*([\d:]+)/i);

//  valores por defecto catch
const fecha = matchFecha ? matchFecha[1].trim() : "";
const hora = matchHora ? matchHora[1].trim() : "";

if (!fecha || !hora) {
    throw new Error("No se pudo extraer la fecha o la hora del mensaje de cancelación.");
}

// crear objeto de fecha base combinando A M D + Hora
const fechaBase = new Date(`${fecha}T${hora}:00`);

// Calculo 30 min
const treintaMinutosEnMilisegundos = 30 * 60 * 1000;

const tiempoAfter = new Date(fechaBase.getTime() - treintaMinutosEnMilisegundos);
const tiempoBefore = new Date(fechaBase.getTime() + treintaMinutosEnMilisegundos);


const formatISO = (date) => {
    return date.toISOString().replace('Z', '-06:00');
};

const afterStr = formatISO(tiempoAfter);
const beforeStr = formatISO(tiempoBefore);

return [{
    json: {
        fecha,
        hora,
        after: afterStr,
        before: beforeStr,
        timeZone: "America/Mexico_City"
    }
}];

const datosAgente = $("AI Agent").first().json;
const texto = datosAgente.output || "";

// 1. Extracción de datos de la cita VIEJA (para buscar y cancelar)
const matchFechaVieja = texto.match(/fecha_vieja:\s*([\d-]+)/i);
const matchHoraVieja = texto.match(/hora_vieja:\s*([\d:]+)/i);

// 2. Extracción de datos de la cita NUEVA (para el flujo de confirmación)
const matchFechaNueva = texto.match(/fecha_nueva:\s*([\d-]+)/i);
const matchHoraNueva = texto.match(/hora_nueva:\s*([\d:]+)/i);

// 3. Extracción de metadatos adicionales
const matchNombre = texto.match(/nombre:\s*(.+)/i);
const matchTratamiento = texto.match(/tratamiento:\s*(.+)/i);
const matchDuracion = texto.match(/duracion:\s*([\d]+)/i);

const fecha_vieja = matchFechaVieja ? matchFechaVieja[1].trim() : "";
const hora_vieja = matchHoraVieja ? matchHoraVieja[1].trim() : "";
const fecha_nueva = matchFechaNueva ? matchFechaNueva[1].trim() : "";
const hora_nueva = matchHoraNueva ? matchHoraNueva[1].trim() : "";
const nombre = matchNombre ? matchNombre[1].trim() : "";
const tratamiento = matchTratamiento ? matchTratamiento[1].trim() : "";
const duracion = matchDuracion ? matchDuracion[1].trim() : "";

if (!fecha_vieja || !hora_vieja || !fecha_nueva || !hora_nueva) {
    throw new Error("Faltan datos de fecha u hora (vieja/nueva) en el mensaje del agente.");
}

// Crear objeto de fecha base usando la cita VIEJA para la búsqueda
const fechaBase = new Date(`${fecha_vieja}T${hora_vieja}:00`);

// Ventana de tiempo optimizada: ±30 MINUTOS (en milisegundos)
const treintaMinutosEnMilisegundos = 30 * 60 * 1000;

const tiempoAfter = new Date(fechaBase.getTime() - treintaMinutosEnMilisegundos);
const tiempoBefore = new Date(fechaBase.getTime() + treintaMinutosEnMilisegundos);

// Convertir a formato ISO local
const formatISO = (date) => {
    return date.toISOString().replace('Z', '-06:00');
};

const afterStr = formatISO(tiempoAfter);
const beforeStr = formatISO(tiempoBefore);

// Devolvemos TODO el paquete completo. Las viejas sirven para el Calendar actual, 
// y las nuevas viajan en el flujo hasta el Edit Fields final.
return [{
    json: {
        fecha_vieja,
        hora_vieja,
        fecha_nueva,
        hora_nueva,
        nombre,
        tratamiento,
        duracion,
        after: afterStr,
        before: beforeStr,
        timeZone: "America/Mexico_City"
    }
}];
